// ── Customer Health Score Calculator ──────────────────────────────
// Weights: Logins 40% | Feature Adoption 35% | Support Tickets 25% (inverse)
// Score range: 0-100. Higher = healthier account.

const accounts = $input.all();

const scored = accounts.map(item => {
  const d = item.json;

  // Normalise each metric to a 0-1 scale
  const loginScore  = Math.min(d.logins_30d / 20, 1) * 40;   // 20+ logins = full points
  const featureScore = Math.min(d.features_used / 10, 1) * 35; // 10+ features = full points
  const ticketPenalty = Math.min(d.support_tickets * 5, 25);   // Each ticket = -5 pts, max -25

  const raw = loginScore + featureScore - ticketPenalty;
  const health_score = Math.round(Math.max(0, Math.min(100, raw)));

  // Risk classification
  let risk_level, grade;
  if (health_score >= 80)      { risk_level = 'safe';  grade = 'A'; }
  else if (health_score >= 60) { risk_level = 'stable'; grade = 'B'; }
  else if (health_score >= 40) { risk_level = 'watch';  grade = 'C'; }
  else                         { risk_level = 'high';   grade = 'D'; }

  return {
    json: {
      account_id:          d.account_id,
      customer_name:       d.customer_name,
      hubspot_company_id:  d.hubspot_company_id,
      health_score,
      risk_level,
      grade,
      scored_at:           new Date().toISOString(),
      // Raw metrics for transparency
      logins_30d:          d.logins_30d,
      features_used:       d.features_used,
      support_tickets:     d.support_tickets
    }
  };
});

return scored;

